_LOCALIZE_BY_LANG: dict[str, dict[str, dict[str, str | list]]] = {
    "de": SELLER_LOCALIZE_DE,
    "fr": SELLER_LOCALIZE_FR,
}


def get_localize_block(slug: str, lang: str) -> dict | None:
    """Return localized seller copy for *slug* in *lang* (de or fr), or None."""
    blocks = _LOCALIZE_BY_LANG.get(lang.lower())
    if blocks is None:
        return None
    return blocks.get(slug)
